<template>
    <div>
        <loader :is-visible="isLoading"></loader>
        <!-- Project row - always show if project has start/end dates -->
        <div v-if="hasProjectDates(project)" 
             :key="`${project.projectId}-PROJECT`"
             class="resource-line project-resource-line" 
             :data-projectid="project.projectId" 
             :data-pkid="project.projectId || ''"
             :data-projectname="project.projectName"
             :data-resource-id="'Project'">
            <div v-for="(period, periodIndex) in calendarPeriods" :key="periodIndex" 
                 class="resources--cal-unit"
                 :class="getPeriodClass(period)"
                 :id="'RImpact_PROJECT_'+periodIndex"
                 :style="getCellWidth()">
                <div style="height: 14px;" class="utilisation"></div>
                <div class="bookings">
                    <!-- Only show project bar in the first period where it starts -->
                    <RoadMapBar 
                        v-if="isProjectStartPeriod(period, periodIndex)"
                        :item="getProjectItem()"
                        type="PROJECT"
                        :day="getProjectStartPeriod().firstDate"
                        :fromDate="fromDate"
                        :toDate="toDate"
                        :activeZoom="activeZoom"
                        :setting="'PROJECT'"
                        :projectId="project.projectId"
                        :currency="project.Currency || project.IsoCode"
                        :calculatedEndDate="null"
                        :calculatedLeaveDays="0"
                        :totalOffDays="0"
                        :regType="''"
                        :isResource="false"
                        :isMilestone="false"
                        :daysDiff="0"
                        :daysBetweenProp="getProjectTotalDays()"
                        :taskProjectId="null"
                        :taskId="null"
                        :taskIsoCode="''"
                        :project="project"
                    />
                </div>
            </div> 
        </div>
        <template v-for="(setting, settingIndex) in selectedSettings">
            <div v-if="shouldShowSetting(setting, project)" 
                 :key="`${project.projectId}-${settingIndex}-${setting}`"
                 class="resource-line" 
                 :data-projectid="project.projectId" 
                 :data-pkid="project.projectId || ''"
                 :data-projectname="project.projectName"
                 :data-resource-id="getSettingName(setting)">
                <div v-for="(period, periodIndex) in calendarPeriods" :key="periodIndex" 
                     class="resources--cal-unit"
                     :class="getPeriodClass(period)"
                     :id="'RImpact_'+periodIndex"
                     :style="getCellWidth()">
                    <div style="height: 14px;" class="utilisation"></div>
                    <div class="bookings">
                        <RoadMapBar 
                            v-for="(itemData, itemIndex) in getItemsForPeriod(setting, period)" 
                            :key="itemIndex"
                            :item="itemData.item"
                            :type="itemData.type"
                            :day="period.firstDate"
                            :fromDate="fromDate"
                            :toDate="toDate"
                            :activeZoom="activeZoom"
                            :setting="setting"
                            :projectId="project.projectId"
                            :currency="project.Currency || project.IsoCode"
                            :calculatedEndDate="itemData.calculatedEndDate"
                            :calculatedLeaveDays="itemData.calculatedLeaveDays"
                            :totalOffDays="itemData.totalOffDays"
                            :regType="itemData.regType"
                            :isResource="itemData.isResource"
                            :isMilestone="itemData.isMilestone"
                            :daysDiff="itemData.daysDiff"
                            :daysBetweenProp="itemData.daysBetween"
                            :taskProjectId="itemData.projectId"
                            :taskId="itemData.taskId"
                            :taskIsoCode="itemData.IsoCode"
                            :project="project"
                        />
                    </div>
                </div> 
            </div>
        </template>
        <div v-if="isTask">
          <EditTask  :projectdata="projectdata" @callbackfunction="callbackfunction" />
        </div>  
    </div>
</template>

<script>    
import RoadMapBar from './RoadMapBar.vue';
import moment from 'moment';        
import EditTask from '../../../components/Modal/EditTask.vue';
export default {
    name: 'RoadMapResourceData',
    components: {
        RoadMapBar,EditTask
    },
    props: {
        project: {
            type: Object,
            required: true
        },
        fromDate: {
            type: Date,
            required: true
        },
        toDate: {
            type: Date,
            required: true
        },
        activeZoom: {
            type: String,
            default: 'Week'
        },
        selectedSettings: {
            type: Array,
            default: () => ['P', 'S', 'TM']
        }
    },
    data(){
         return{
            isLoading:false,
            isTask:false,
            projectdata:[],
         }
    },
    computed: {
        calendarPeriods() {
            switch(this.activeZoom) {
                case 'Week':
                    return this.generateWeekPeriods();
                case 'Month':
                    return this.generateMonthPeriods();
                case 'Quarter':
                    return this.generateQuarterPeriods();
                case 'Year':
                    return this.generateYearPeriods();
                default:
                    return this.generateWeekPeriods();
            }
        }
    },    
    methods: {
        callbackfunction()
        {
             this.isTask=false;
             this.projectdata=[];
             this.$root.$emit('call-SearchRoadMapCall', { action: 'update',ProjectId:this.project.projectId});
             
        },
        // ReloadList()
        // {
        //     this.$emit('call-SearchRoadMap');
        // },
        shouldShowSetting(setting, project) {
            if (!project) return false;
            
            // Always show rows for selected settings if property exists, even if arrays are empty or null
            // This ensures calendar structure is always created
            switch(setting) {
                case 'P':
                    // Show Phase row if property exists (even if null/empty array)
                    return ('listPhase' in project) || ('ListPhase' in project);
                case 'S':
                    // Show Stage row if property exists (even if null/empty array)
                    return ('listStage' in project) || ('ListStage' in project);
                case 'TM':
                    // Show Task/Milestone row if property exists (even if null/empty array)
                    return ('listTask' in project) || ('ListTask' in project) ||
                           ('listMilestone' in project) || ('ListMilestone' in project) ||
                           ('ListMileStone' in project);
                default:
                    return false;
            }
        },
        getSettingName(setting) {
            switch(setting) {
                case 'P':
                    return 'Phase';
                case 'S':
                    return 'Stage';
                case 'TM':
                    return 'Task/Milestone';
                default:
                    return '';
            }
        },
        hasProjectDates(project) {
            // Check if project has start and end dates
            return project && (project.projectStartDate || project.projectEndDate);
        },
        getProjectItem() {
            // Create project item object
            return {
                Name: this.project.projectName || 'Project',
                name: this.project.projectName || 'Project',
                startDate: this.project.projectStartDate,
                endDate: this.project.projectEndDate,
                StartDate: this.project.projectStartDate,
                EndDate: this.project.projectEndDate,
                type: 'PROJECT',
                Type: 'PROJECT',
                projectId: this.project.projectId,
                pkId: this.project.projectId
            };
        },
        getProjectStartPeriod() {
            // Find the first period where the project starts
            if (!this.project || (!this.project.projectStartDate && !this.project.projectEndDate)) {
                return this.calendarPeriods[0] || {};
            }
            
            const projectStartDate = this.epochToDateTime(this.project.projectStartDate);
            if (!projectStartDate || isNaN(projectStartDate.getTime())) {
                return this.calendarPeriods[0] || {};
            }
            
            const projectStart = new Date(projectStartDate);
            projectStart.setHours(0, 0, 0, 0);
            
            // Find the first period that contains or starts after the project start date
            for (let i = 0; i < this.calendarPeriods.length; i++) {
                const period = this.calendarPeriods[i];
                const periodStart = new Date(period.firstDate);
                periodStart.setHours(0, 0, 0, 0);
                const periodEnd = new Date(period.lastDate);
                periodEnd.setHours(23, 59, 59, 999);
                
                // Check if project starts in this period
                if (projectStart >= periodStart && projectStart <= periodEnd) {
                    return period;
                }
                // If project starts before this period, use this period
                if (projectStart < periodStart) {
                    return period;
                }
            }
            
            // Default to first period
            return this.calendarPeriods[0] || {};
        },
        isProjectStartPeriod(period, periodIndex) {
            // Only show project bar in the period where it starts
            const startPeriod = this.getProjectStartPeriod();
            return period.firstDate.getTime() === startPeriod.firstDate.getTime();
        },
        getProjectTotalDays() {
            // Calculate total days from project start to end date
            if (!this.project || (!this.project.projectStartDate && !this.project.projectEndDate)) {
                return 0;
            }
            
            const ss_fromdate = new Date(this.fromDate);
            const ss_endDate = new Date(this.toDate);
            
            const projectStartDate = this.epochToDateTime(this.project.projectStartDate);
            const projectEndDate = this.epochToDateTime(this.project.projectEndDate);
            
            if (!projectStartDate || isNaN(projectStartDate.getTime())) {
                return 0;
            }
            
            const projectStart = new Date(projectStartDate);
            projectStart.setHours(0, 0, 0, 0);
            const projectEnd = projectEndDate ? new Date(projectEndDate) : new Date(projectStart);
            projectEnd.setHours(23, 59, 59, 999);
            
            // Calculate effective dates within the visible range
            const effectiveStart = projectStart < ss_fromdate ? ss_fromdate : projectStart;
            const effectiveEnd = projectEnd > ss_endDate ? ss_endDate : projectEnd;
            
            return this.daysBetweenDates(effectiveStart, effectiveEnd);
        },
       
        editask(project,task)
        { 
            debugger
            this.isLoading=true;
            this.projectdata=[];
            this.projectdata={
                task_id:project.task_id,
                project_id:project.project_id,
                task_type:'T',
                priority_name:task.prioritY_NAME,
                priority_id:task.prioritY_ID,
                task_name:task.name,
                task_description:task.desc,
                planned_start_date:this.formatDate(task.startDate),
                planned_end_date:this.formatDate(task.endDate),
                status_id:1001,
                status_name:task.statuS_NAME,
                parent_task_id:0
            };
            this.isTask=true;
            setTimeout(function () {
                $("#modalEditTask").modal("show");
            }, 1000); 
            this.isLoading=false;
        },
        formatDate(dateValue) {
            if (!dateValue) return '';

            let date;

            // If value is numeric or numeric string
            if (!isNaN(dateValue)) {
                dateValue = dateValue.toString();

                // If timestamp is in seconds (10 digits) → convert to milliseconds
                date = dateValue.length === 10 
                    ? new Date(parseInt(dateValue) * 1000) 
                    : new Date(parseInt(dateValue));
            } else {
                // For normal date strings
                date = new Date(dateValue);
            }
            if (isNaN(date.getTime())) return '';

            return moment(date).format('MM/DD/YYYY');
        },
        getItemsForPeriod(setting, period) {
            const result = [];
            const periodStart = new Date(period.firstDate);
            const periodEnd = new Date(period.lastDate);
            periodStart.setHours(0, 0, 0, 0);
            periodEnd.setHours(23, 59, 59, 999);
            const firstday = new Date(periodStart);
            const ss_fromdate = new Date(this.fromDate);
            const ss_endDate = new Date(this.toDate);
            
            // Helper function to check if date ranges overlap
            const dateRangesOverlap = (itemStart, itemEnd, periodStart, periodEnd) => {
                return itemStart <= periodEnd && itemEnd >= periodStart;
            };
            
            // Helper function to check if item should be shown in this period
            const shouldShowItem = (itemStart, itemEnd, periodStart, periodEnd, firstday) => {
                // For Week view, check exact match (original behavior)
                if (this.activeZoom === 'Week') {
                    return itemStart.setHours(0, 0, 0, 0) === firstday.setHours(0, 0, 0, 0);
                }
                // For Month, Quarter, Year views, check if date ranges overlap
                return dateRangesOverlap(itemStart, itemEnd, periodStart, periodEnd);
            };
            
            // Handle Phase (P) - Show phases from listPhase array
            if (setting === 'P') {
                // Normalize array - handle null/undefined/empty arrays
                const phases = Array.isArray(this.project.listPhase) ? this.project.listPhase : 
                              (Array.isArray(this.project.ListPhase) ? this.project.ListPhase : []);
                
                // If array is empty, still create the row structure but with no items
                if (!phases || phases.length === 0) {
                    return result; // Return empty result, but row structure will still be created
                }
                
                phases.forEach(phase => {                    
                    const phaseStartDate = this.epochToDateTime(phase.startDate);
                    const phaseEndDate = this.epochToDateTime(phase.endDate);                    
                    if (!phaseStartDate || isNaN(phaseStartDate.getTime())) return;                    
                    // Check if phase overlaps with period (more flexible than exact match)
                    const phaseStart = new Date(phaseStartDate);
                    phaseStart.setHours(0, 0, 0, 0);
                    const phaseEnd = phaseEndDate ? new Date(phaseEndDate) : new Date(phaseStart);
                    phaseEnd.setHours(23, 59, 59, 999);
                    
                    // Check if phase should be shown in this period
                    if (shouldShowItem(phaseStart, phaseEnd, periodStart, periodEnd, firstday)) {
                        if (phase.startDate) {
                            const effectiveStart = phase.startDate == null ? ss_fromdate : phaseStart;
                            const effectiveEnd = phase.endDate == null ? ss_endDate : phaseEnd;
                            const $daysbwDates = this.daysBetweenDates(
                                effectiveStart < firstday ? firstday : effectiveStart,
                                effectiveEnd > ss_endDate ? ss_endDate : effectiveEnd
                            );
                            phase.type='P';
                            result.push({
                                item: phase,
                                calculatedEndDate: this.epochToDateTime(phase.CalculatedEndDate || phase.calculatedEndDate),
                                calculatedLeaveDays: phase.CalculatedLeaveDays || 0,
                                totalOffDays: phase.TotalOffDays || 0,
                                daysBetween: $daysbwDates,
                                isResource: false,
                                isPhase: true
                            });
                        }
                    }
                });
            }
            // Handle Stage (S)
            else if (setting === 'S') {
                // Normalize array - handle null/undefined/empty arrays
                const stages = Array.isArray(this.project.listStage) ? this.project.listStage : 
                              (Array.isArray(this.project.ListStage) ? this.project.ListStage : []);
                
                // If array is empty, still create the row structure but with no items
                if (!stages || stages.length === 0) {
                    return result; // Return empty result, but row structure will still be created
                }
                
                stages.forEach(stage => {
                    const stageStartDate = this.epochToDateTime(stage.StartDate || stage.startDate);
                    const stageEndDate = this.epochToDateTime(stage.EndDate || stage.endDate);
                    
                    if (!stageStartDate || isNaN(stageStartDate.getTime())) return;
                    
                    const stageStart = new Date(stageStartDate);
                    stageStart.setHours(0, 0, 0, 0);
                    const stageEnd = stageEndDate ? new Date(stageEndDate) : new Date(stageStart);
                    stageEnd.setHours(23, 59, 59, 999);
                    
                    // Check if stage should be shown in this period
                    if (shouldShowItem(stageStart, stageEnd, periodStart, periodEnd, firstday)) {
                        if (stage.StartDate || stage.startDate) {
                            const effectiveStart = (stage.StartDate == null && stage.startDate == null) ? ss_fromdate : stageStart;
                            const effectiveEnd = (stage.EndDate == null && stage.endDate == null) ? ss_endDate : stageEnd;
                            const $daysbwDates = this.daysBetweenDates(
                                effectiveStart < firstday ? firstday : effectiveStart,
                                effectiveEnd > ss_endDate ? ss_endDate : effectiveEnd
                            );
                            stage.type = 'S';
                            result.push({
                                item: stage,
                                calculatedEndDate: this.epochToDateTime(stage.CalculatedEndDate || stage.calculatedEndDate),
                                calculatedLeaveDays: stage.CalculatedLeaveDays || stage.calculatedLeaveDays || 0,
                                totalOffDays: stage.TotalOffDays || stage.totalOffDays || 0,
                                daysBetween: $daysbwDates,
                                isResource: false
                            });
                        }
                    }
                });
            }
            // Handle Task/Milestone (TM) - j == 1 and j == 2 in original function
            else if (setting === 'TM') {
                // Handle Tasks (j == 1)
                // Normalize array - handle null/undefined/empty arrays
                const tasks = Array.isArray(this.project.listTask) ? this.project.listTask : 
                             (Array.isArray(this.project.ListTask) ? this.project.ListTask : []);
                const IsoCode = this.project.IsoCode || this.project.Currency || '';
                
                // Process tasks if array exists and has items
                if (tasks && tasks.length > 0) {
                    tasks.forEach(value => {
                    const stageStartDate = this.epochToDateTime(value.startDate);
                    const stageEndDate = this.epochToDateTime(value.endDate);
                    const taskCalcudatedEndDate = this.epochToDateTime(value.CalculatedEndDate || value.calculatedEndDate);
                    
                    if (!stageStartDate || isNaN(stageStartDate.getTime())) return;
                    
                    const projectId = value.Task_Project_Id || value.task_Project_Id || this.project.projectId;
                    const taskId = value.Task_Id || value.task_Id;
                    const daysDiff = taskCalcudatedEndDate && stageEndDate ? (taskCalcudatedEndDate - stageEndDate) / (1000 * 60 * 60 * 24) : 0;
                    
                    const taskStart = new Date(stageStartDate);
                    taskStart.setHours(0, 0, 0, 0);
                    const taskEnd = stageEndDate ? new Date(stageEndDate) : new Date(taskStart);
                    taskEnd.setHours(23, 59, 59, 999);
                    
                    // Check if task should be shown in this period
                    if (shouldShowItem(taskStart, taskEnd, periodStart, periodEnd, firstday)) {
                            if (value.startDate) {
                                const listResourcePlan = value.ListResourcePlan || value.listResourcePlan || [];
                                
                                // If task has resource plans, add task for each resource plan
                                if (listResourcePlan.length > 0) {
                                    listResourcePlan.forEach(valueR => {
                                        const effectiveStartDate = value.startDate == null ? ss_fromdate : stageStartDate;
                                        const effectiveEndDate = value.EndDate == null ? ss_endDate : stageEndDate;
                                        const $daysbwCalcudatedLeaveDates = daysDiff;
                                        const RPlanCalcudatedEndDate = this.epochToDateTime(valueR.CalculatedEndDate || valueR.calculatedEndDate);
                                        const checkCalculatedEndDate = new Date(RPlanCalcudatedEndDate);
                                        const checktaskCalcudatedEndDate = new Date(taskCalcudatedEndDate);
                                        const $daysbwDates = this.daysBetweenDates(
                                            effectiveStartDate < firstday ? firstday : effectiveStartDate,
                                            effectiveEndDate > ss_endDate ? ss_endDate : effectiveEndDate
                                        );
                                        
                                        let daysDiffOfTask = 0;
                                        let finalDays = $daysbwDates;
                                        
                                        if (checkCalculatedEndDate > checktaskCalcudatedEndDate) {
                                            daysDiffOfTask = Math.ceil((RPlanCalcudatedEndDate.setHours(0, 0, 0) - taskCalcudatedEndDate.setHours(0, 0, 0)) / (1000 * 60 * 60 * 24));
                                            finalDays = $daysbwDates + daysDiffOfTask;
                                        } else {
                                            finalDays = $daysbwDates + $daysbwCalcudatedLeaveDates;
                                        }
                                        
                                        result.push({
                                            item: value,
                                            calculatedEndDate: taskCalcudatedEndDate,
                                            calculatedLeaveDays: daysDiff,
                                            daysDiff: daysDiffOfTask,
                                            daysBetween: finalDays,
                                            regType: value.RegType || value.regType,
                                            isResource: false,
                                            isTask: true,
                                            projectId: projectId,
                                            taskId: taskId,
                                            IsoCode: IsoCode
                                        });
                                    });
                                } else {
                                    // Task without resource plans - add it directly
                                    const effectiveStartDate = value.StartDate == null ? ss_fromdate : stageStartDate;
                                    const effectiveEndDate = value.EndDate == null ? ss_endDate : stageEndDate;
                                    const $daysbwDates = this.daysBetweenDates(
                                        effectiveStartDate < firstday ? firstday : effectiveStartDate,
                                        effectiveEndDate > ss_endDate ? ss_endDate : effectiveEndDate
                                    );
                                    const finalDays = $daysbwDates + daysDiff;
                                    
                                    result.push({
                                        item: value,
                                        calculatedEndDate: taskCalcudatedEndDate,
                                        calculatedLeaveDays: daysDiff,
                                        daysDiff: 0,
                                        daysBetween: finalDays,
                                        regType: value.RegType || value.regType,
                                        isResource: false,
                                        isTask: true,
                                        projectId: projectId,
                                        taskId: taskId,
                                        IsoCode: IsoCode,
                                        type: 'TM'
                                    });
                                }                                
                                // Handle Resource Plans separately (nested under tasks in original code)
                                listResourcePlan.forEach(resourceValue => {
                                    const resourceStartDate = this.epochToDateTime(resourceValue.StartDate || resourceValue.startDate);
                                    const resourceEndDate = this.epochToDateTime(resourceValue.EndDate || resourceValue.endDate);
                                    const resourceCalcudatedEndDate = this.epochToDateTime(resourceValue.CalculatedEndDate || resourceValue.calculatedEndDate);
                                    
                                    if (!resourceStartDate || isNaN(resourceStartDate.getTime())) return;
                                    
                                    const resourceDaysDiff = resourceCalcudatedEndDate && resourceEndDate ? 
                                        (resourceCalcudatedEndDate - resourceEndDate) / (1000 * 60 * 60 * 24) : 0;
                                    
                                    const resourceStart = new Date(resourceStartDate);
                                    resourceStart.setHours(0, 0, 0, 0);
                                    const resourceEnd = resourceEndDate ? new Date(resourceEndDate) : new Date(resourceStart);
                                    resourceEnd.setHours(23, 59, 59, 999);
                                    
                                    // Check if resource plan should be shown in this period
                                    if (shouldShowItem(resourceStart, resourceEnd, periodStart, periodEnd, firstday)) {
                                            if (resourceValue.StartDate) {
                                                const effectiveResourceStart = resourceValue.StartDate == null ? ss_fromdate : resourceStartDate;
                                                const effectiveResourceEnd = resourceValue.EndDate == null ? ss_endDate : resourceEndDate;
                                                const $daysbwCalcudatedLeaveDates = Math.ceil(resourceDaysDiff);
                                                const $daysbwDates = this.daysBetweenDates(
                                                    effectiveResourceStart < firstday ? firstday : effectiveResourceStart,
                                                    effectiveResourceEnd > ss_endDate ? ss_endDate : effectiveResourceEnd
                                                );
                                                const finalResourceDays = $daysbwDates + $daysbwCalcudatedLeaveDates;
                                                
                                                result.push({
                                                    item: resourceValue,
                                                    calculatedEndDate: resourceCalcudatedEndDate,
                                                    calculatedLeaveDays: $daysbwCalcudatedLeaveDates,
                                                    daysDiff: resourceDaysDiff,
                                                    daysBetween: finalResourceDays,
                                                    regType: resourceValue.RegType || resourceValue.regType,
                                                    isResource: true,
                                                    parentTask: value
                                                });
                                            }
                                        }
                                    });
                            }
                        }
                    });
                }
                
                // Handle Milestones (j == 2)
                // Normalize array - handle null/undefined/empty arrays
                const milestones = Array.isArray(this.project.listMilestone) ? this.project.listMilestone : 
                                  (Array.isArray(this.project.ListMilestone) ? this.project.ListMilestone : 
                                  (Array.isArray(this.project.ListMileStone) ? this.project.ListMileStone : []));
                
                // Process milestones if array exists and has items
                if (milestones && milestones.length > 0) {
                    milestones.forEach(milestone => {
                    const milestoneStartDate = this.epochToDateTime(milestone.StartDate || milestone.startDate);
                    const milestoneEndDate = this.epochToDateTime(milestone.EndDate || milestone.endDate);                    
                    if (!milestoneStartDate || isNaN(milestoneStartDate.getTime())) return;
                    
                    const milestoneStart = new Date(milestoneStartDate);
                    milestoneStart.setHours(0, 0, 0, 0);
                    const milestoneEnd = milestoneEndDate ? new Date(milestoneEndDate) : new Date(milestoneStart);
                    milestoneEnd.setHours(23, 59, 59, 999);
                    
                    // Check if milestone should be shown in this period
                    if (shouldShowItem(milestoneStart, milestoneEnd, periodStart, periodEnd, firstday)) {
                        if (milestone.StartDate) {
                            const effectiveStart = milestone.startDate == null ? ss_fromdate : milestoneStart;
                            const effectiveEnd = milestone.endDate == null ? ss_endDate : milestoneEnd;
                            const $daysbwDates = this.daysBetweenDates(
                                effectiveStart < firstday ? firstday : effectiveStart,
                                effectiveEnd > ss_endDate ? ss_endDate : effectiveEnd
                            );
                            
                            result.push({
                                item: milestone,
                                calculatedEndDate: null,
                                daysBetween: $daysbwDates,
                                isResource: false,
                                isMilestone: true,
                                type: 'TM'
                            });
                        }
                    }
                    });
                }
            }
            return result;
        },
        generateDayPeriods() {
            const periods = [];
            const start = new Date(this.fromDate);
            const end = new Date(this.toDate);
            start.setHours(0, 0, 0, 0);
            end.setHours(23, 59, 59, 999);
            let current = new Date(start);
            
            // Safety counter to prevent infinite loops (max 10 years = ~3650 days)
            let maxIterations = 3650;
            let iterationCount = 0;
            
            while (current <= end && iterationCount < maxIterations) {
                const dayDate = new Date(current);
                periods.push({
                    firstDate: new Date(dayDate),
                    lastDate: new Date(dayDate)
                });
                current.setDate(current.getDate() + 1);
                iterationCount++;
            }
            
            return periods;
        },
        generateWeekPeriods() {
            // Week view: Generate periods for each day (7 days per week)
            const periods = [];
            const start = new Date(this.fromDate);
            const end = new Date(this.toDate);
            start.setHours(0, 0, 0, 0);
            end.setHours(23, 59, 59, 999);
            
            // Get first day of week
            let first = start.getDate() - start.getDay() + 1;
            let currentWeekStart = new Date(start);
            currentWeekStart.setDate(first);
            currentWeekStart.setHours(0, 0, 0, 0);
            
            let dayIndex = 0;
            while (currentWeekStart <= end) {
                const weekEnd = new Date(currentWeekStart);
                weekEnd.setDate(weekEnd.getDate() + 6);
                weekEnd.setHours(23, 59, 59, 999);
                
                // Generate 7 days for this week
                let dayCounter = new Date(currentWeekStart);
                for (let j = 0; j < 7 && dayCounter <= end; j++) {
                    const dayDate = new Date(dayCounter);
                    dayDate.setHours(0, 0, 0, 0);
                    
                    periods.push({
                        firstDate: new Date(dayDate),
                        lastDate: new Date(dayDate),
                        dayIndex: dayIndex
                    });
                    
                    dayCounter.setDate(dayCounter.getDate() + 1);
                    dayIndex++;
                }
                
                currentWeekStart.setDate(currentWeekStart.getDate() + 7);
            }
            
            return periods;
        },
        // Helper to add days (matching addDays from JavaScript)
        addDays(date, days) {
            const result = new Date(date);
            result.setDate(result.getDate() + days);
            return result;
        },
        generateMonthPeriods() {
            // Month view: Generate periods for each week (4 weeks per month)
            const periods = [];
            const start = new Date(this.fromDate);
            const end = new Date(this.toDate);
            start.setHours(0, 0, 0, 0);
            end.setHours(23, 59, 59, 999);
            
            const monthdiff = this.monthDifference(start, end);
            
            for (let i = 0; i < monthdiff; i++) {
                const monthStart = new Date(start.getFullYear(), start.getMonth() + i, 1);
                const monthEnd = new Date(start.getFullYear(), start.getMonth() + i + 1, 0);
                monthEnd.setHours(23, 59, 59, 999);
                
                // Get first day of week for month start
                let weekStart = new Date(monthStart);
                const firstDayOfWeek = weekStart.getDay();
                weekStart.setDate(weekStart.getDate() - firstDayOfWeek);
                weekStart.setHours(0, 0, 0, 0);
                
                // Generate weeks for the month (max 4 weeks)
                let currentWeek = new Date(weekStart);
                let weekCount = 0;
                
                while (currentWeek <= monthEnd && weekCount < 4) {
                    const weekEnd = new Date(currentWeek);
                    weekEnd.setDate(weekEnd.getDate() + 6);
                    weekEnd.setHours(23, 59, 59, 999);
                    
                    // Only include weeks that overlap with the month
                    if (weekEnd >= monthStart && currentWeek <= monthEnd) {
                        periods.push({
                            firstDate: new Date(currentWeek),
                            lastDate: new Date(weekEnd),
                            firstDateFormatted: `${currentWeek.getFullYear()}-${currentWeek.getMonth() + 1}-${currentWeek.getDate()}`,
                            lastDateFormatted: `${weekEnd.getFullYear()}-${weekEnd.getMonth() + 1}-${weekEnd.getDate()}`
                        });
                        weekCount++;
                    }
                    
                    currentWeek.setDate(currentWeek.getDate() + 7);
                }
            }
            
            return periods;
        },
        generateQuarterPeriods() {
            // Quarter view: Generate ALL months for each quarter in the date range
            // This is similar to Year view - shows full quarters regardless of start/end dates
            const periods = [];
            const start = new Date(this.fromDate);
            const end = new Date(this.toDate);
            start.setHours(0, 0, 0, 0);
            end.setHours(23, 59, 59, 999);
            
            // Calculate quarters
            const startQuarter = Math.floor(start.getMonth() / 3);
            const endQuarter = Math.floor(end.getMonth() / 3);
            const startYear = start.getFullYear();
            const endYear = end.getFullYear();
            
            let currentYear = startYear;
            let currentQuarter = startQuarter;
            
            // Generate ALL months for ALL quarters in the range
            while (currentYear < endYear || (currentYear === endYear && currentQuarter <= endQuarter)) {
                const quarterStartMonth = currentQuarter * 3;
                
                // Generate ALL 3 months for this quarter (regardless of start/end dates)
                for (let m = 0; m < 3; m++) {
                    const monthStart = new Date(currentYear, quarterStartMonth + m, 1);
                    const monthEnd = new Date(currentYear, quarterStartMonth + m + 1, 0);
                    monthEnd.setHours(23, 59, 59, 999);
                    
                    // Add all months (full months, not capped)
                    periods.push({
                        firstDate: new Date(monthStart),
                        lastDate: new Date(monthEnd),
                        firstDateFormatted: `${monthStart.getFullYear()}-${monthStart.getMonth() + 1}-1`,
                        lastDateFormatted: `${monthEnd.getFullYear()}-${monthEnd.getMonth() + 1}-${monthEnd.getDate()}`
                    });
                }
                
                currentQuarter++;
                if (currentQuarter > 3) {
                    currentQuarter = 0;
                    currentYear++;
                }
            }
            
            return periods;
        },
        generateYearPeriods() {
            // Year view: Generate ALL quarters for each year in the date range
            // This is different from Week/Month views which respect exact dates
            const periods = [];
            const start = new Date(this.fromDate);
            const end = new Date(this.toDate);
            start.setHours(0, 0, 0, 0);
            end.setHours(23, 59, 59, 999);
            
            const yeardiff = this.yearDifference(start, end);
            
            // Generate all quarters for all years in the range
            for (let i = 0; i < yeardiff; i++) {
                const yearStart = new Date(start.getFullYear() + i, 0, 1);
                const yearEnd = new Date(start.getFullYear() + i, 11, 31);
                yearEnd.setHours(23, 59, 59, 999);
                
                // Generate ALL 4 quarters for this year (regardless of start/end dates)
                for (let q = 0; q < 4; q++) {
                    const quarterStartMonth = q * 3;
                    const quarterStart = new Date(yearStart.getFullYear(), quarterStartMonth, 1);
                    const quarterEnd = new Date(yearStart.getFullYear(), quarterStartMonth + 3, 0);
                    quarterEnd.setHours(23, 59, 59, 999);
                    
                    // Add all quarters (full quarters, not capped)
                    periods.push({
                        firstDate: new Date(quarterStart),
                        lastDate: new Date(quarterEnd),
                        firstDateFormatted: `${quarterStart.getFullYear()}-${quarterStart.getMonth() + 1}-1`,
                        lastDateFormatted: `${quarterEnd.getFullYear()}-${quarterEnd.getMonth() + 1}-${quarterEnd.getDate()}`
                    });
                }
            }
            
            return periods;
        },
        getColumnWidth() {
            // Match plotWidth values for new structure
            switch(this.activeZoom) {
                case 'Week':
                    return 65; // Day columns in week view
                case 'Month':
                    return 103.125; // Week columns in month view (wider than day columns)
                case 'Quarter':
                    return 275; // Month columns in quarter view
                case 'Year':
                    return 206.25; // Quarter columns in year view
                default:
                    return 30;
            }
        },
        getCellWidth() {
            const width = this.getColumnWidth();
            return {
                width: width + 'px',
                minWidth: width + 'px'
            };
        },
        getPeriodClass(period) {
            const classes = [];
            // Weekend detection only applies to Week view (day columns)
            if (this.activeZoom === 'Week' && period.dayIndex !== undefined) {
                const itr = (period.dayIndex % 7) + 1;
                // Weekend check: itr == 6 || itr == 7 means Saturday (6) or Sunday (7)
                if (itr === 6 || itr === 7) {
                    classes.push('unavailable');
                }
            } else if (this.activeZoom === 'Week') {
                // Fallback: calculate from date
                const day = new Date(period.firstDate).getDay();
                const itr = day === 0 ? 7 : day + 1;
                if (itr === 6 || itr === 7) {
                    classes.push('unavailable');
                }
            }
            
            // Check for leave day (only if not already unavailable and in Week view)
            if (this.activeZoom === 'Week' && !classes.includes('unavailable') && this.isLeaveDay(period.firstDate)) {
                classes.push('leaveday');
            }
            
            return classes;
        },
        isWeekendPeriod(period) {
            // For day view, check if it's weekend
            if (this.activeZoom === 'Day') {
                const day = new Date(period.firstDate).getDay();
                return day === 0 || day === 6;
            }
            return false;
        },
        parseDate(dateValue) {
            if (!dateValue) return null;
            if (dateValue instanceof Date) return dateValue;
            if (typeof dateValue === 'number') {
                return dateValue.toString().length >= 13 
                    ? new Date(dateValue) 
                    : new Date(dateValue * 1000);
            }
            if (typeof dateValue === 'string') {
                return new Date(dateValue);
            }
            return null;
        },
        isSameDay(date1, date2) {
            if (!date1 || !date2) return false;
            const d1 = new Date(date1);
            const d2 = new Date(date2);
            d1.setHours(0, 0, 0, 0);
            d2.setHours(0, 0, 0, 0);
            return d1.getTime() === d2.getTime();
        },
        // Helper method: Convert epoch timestamp to Date (matching EpochToDateTime from JavaScript)
        epochToDateTime(epochValue) {
            if (!epochValue) return new Date(0);
            if (epochValue instanceof Date) return epochValue;
            
            // If it's an object with EpochToDateTime method (from JavaScript prototype extension)
            if (typeof epochValue === 'object' && epochValue.EpochToDateTime && typeof epochValue.EpochToDateTime === 'function') {
                return epochValue.EpochToDateTime();
            }
            
            // Handle number (epoch timestamp)
            if (typeof epochValue === 'number') {
                return epochValue.toString().length >= 13 
                    ? new Date(epochValue) 
                    : new Date(epochValue * 1000);
            }
            
            // Handle string that might be a number
            if (typeof epochValue === 'string' && /^\d+$/.test(epochValue)) {
                const num = parseInt(epochValue, 10);
                return num.toString().length >= 13 ? new Date(num) : new Date(num * 1000);
            }
            
            // Try to parse as date string
            if (typeof epochValue === 'string') {
                return new Date(epochValue);
            }
            
            return new Date(0);
        },
        // Helper method: Calculate days between two dates (matching DaysBetweenDates from JavaScript)
        daysBetweenDates(startDate, endDate) {
            if (!startDate || !endDate) return 0;
            // Match original: hours*minutes*seconds*milliseconds
            const oneDay = 24 * 60 * 60 * 1000;
            const firstDate = new Date(startDate);
            firstDate.setHours(0, 0, 0, 0);
            const secondDate = new Date(endDate);
            secondDate.setHours(0, 0, 0, 0);
            const diffDays = Math.round(Math.abs((firstDate.getTime() - secondDate.getTime()) / oneDay));
            return diffDays + 1; // Match original: returns diffDays + 1
        },
        // Helper method: Calculate weeks between two dates (matching WeekDaysBetweenDates from JavaScript)
        weekDaysBetweenDates(fromDate, toDate) {
            if (!fromDate || !toDate) return 0;
            // The number of milliseconds in one week
            const ONE_WEEK = 1000 * 60 * 60 * 24 * 7;
            // Convert both dates to milliseconds
            const date1_ms = fromDate.getTime();
            const date2_ms = toDate.getTime();
            // Calculate the difference in milliseconds
            const difference_ms = Math.abs(date2_ms - date1_ms);
            // Convert back to weeks and return whole weeks
            return Math.floor(difference_ms / ONE_WEEK) + 1;
        },
        // Check if a date is within leave period
        isLeaveDay(date) {
            // In original code, leaveStartDate and leaveEndDate come from options
            // For now, we'll check if there's a leave period defined
            // This should be passed as props or from parent component
            if (this.$parent && this.$parent.options) {
                const leaveStartDate = this.$parent.options.LeaveStartDate;
                const leaveEndDate = this.$parent.options.LeaveEndDate;
                if (!leaveStartDate || !leaveEndDate) return false;
                
                const checkDate = new Date(date);
                checkDate.setHours(0, 0, 0, 0);
                const leaveStart = new Date(leaveStartDate);
                leaveStart.setHours(0, 0, 0, 0);
                const leaveEnd = new Date(leaveEndDate);
                leaveEnd.setHours(0, 0, 0, 0);
                return checkDate >= leaveStart && checkDate <= leaveEnd;
            }
            return false;
        },
        // Helper: Get first day of month
        firstDayInMonth(date) {
            return new Date(date.getFullYear(), date.getMonth(), 1);
        },
        // Helper: Get last day of month
        lastDayInMonth(date) {
            return new Date(date.getFullYear(), date.getMonth() + 1, 0);
        },
        // Helper: Calculate month difference
        monthDifference(fromDate, toDate) {
            if (!fromDate || !toDate) return 0;
            const from = new Date(fromDate);
            const to = new Date(toDate);
            const yearDiff = to.getFullYear() - from.getFullYear();
            const monthDiff = to.getMonth() - from.getMonth();
            return yearDiff * 12 + monthDiff + 1;
        },
        // Helper: Calculate year difference
        yearDifference(fromDate, toDate) {
            if (!fromDate || !toDate) return 0;
            const from = new Date(fromDate);
            const to = new Date(toDate);
            return to.getFullYear() - from.getFullYear() + 1;
        }
    }
}
</script>

