
    <template>
        <aside class="sidebar-content">           
            <div v-for="(project, projectIndex) in roadMapData" :key="projectIndex" class="resourcemain">  
                <div class="flying" v-if="project.projectName">
                    <strong>{{ TruncateStr(project.projectName,20) }}</strong>
                   
                    <a href="javascript:;" class="float-right smallediticon projectEditUpdate" @click="ProjectDetail(project)"><em class="fa fa-pencil-square-o text-success font-20"></em></a>
                     <br>
                    <span v-if="project.projectStartDate && project.projectEndDate">
                        {{ formatDate(project.projectStartDate) }} - {{ formatDate(project.projectEndDate) }}
                    </span>                    
                </div>   
                <template v-for="(setting, settingIndex) in selectedSettings">
                    <div v-if="shouldShowSetting(setting, project)" 
                        :key="`${projectIndex}-${settingIndex}-${setting}`"
                        class="resource flyingdown" 
                        :data-projectid="project.projectId" 
                        :data-resource-id="getSettingName(setting)"
                        :style="{ height: getDynamicHeight(setting) + 'px', lineHeight: getDynamicHeight(setting) + 'px', padding: '0 10px' }">
                        <strong v-if="setting=='P'">Phase</strong>  
                        <strong v-if="setting=='S'">Stage</strong>  
                        <strong v-if="setting=='TM'">Task/Milestone</strong>  
                    </div>
                </template>
            </div>   
        </aside>
      
    </template>
<script>
import moment from 'moment';
export default {
    name: 'RoadMapSidebar',
    props: {
        roadMapData: {
            type: Array,
            default: () => []
        },
        selectedSettings: {
            type: Array,
            default: () => ['P', 'S', 'TM']
        },
        activeZoom: {
            type: String,
            default: 'Week'
        }
    },
    data() {
        return {
            resourceLineHeights: {}, // Cache for resource-line heights
            heightObserver: null // MutationObserver for watching DOM changes
        }
    },
    computed: {
        
    },
    mounted() {
        // Watch for changes and update heights dynamically
        this.updateHeightsFromDOM();
        
        // Update heights when zoom changes
        this.$watch('activeZoom', () => {
            this.updateHeightsFromDOM();
        });
        
        // Update heights when roadMapData changes
        this.$watch('roadMapData', () => {
            this.updateHeightsFromDOM();
        }, { deep: true });
        
        // Use MutationObserver to watch for DOM changes in resource-lines
        this.setupHeightObserver();
    },
    beforeDestroy() {
        // Clean up observer
        if (this.heightObserver) {
            this.heightObserver.disconnect();
        }
    },
    methods: {
        ProjectDetail(project) {
            this.$parent.HandlerEvent(project.projectId);
        },
        formatDate(dateValue) {
            if (!dateValue) return '';

            let timestamp = dateValue;

            // Convert string numeric timestamps to number
            if (typeof timestamp === 'string' && /^\d+$/.test(timestamp)) {
                timestamp = Number(timestamp);
            }

            let date;

            // timestamp in seconds (10 digits) OR milliseconds (13 digits)
            if (typeof timestamp === 'number') {
                date = timestamp.toString().length === 10
                    ? new Date(timestamp * 1000)   // seconds → ms
                    : new Date(timestamp);         // already ms
            } else {
                date = new Date(timestamp);
            }

            return moment(date).format('MM/DD/YYYY');
        },
        shouldShowSetting(setting, project) {
            if (!project) return false;
            
            // Always show rows for selected settings if property exists, even if arrays are empty or null
            // This ensures calendar structure is always created
            switch(setting) {
                case 'P':
                    // Show Phase row if property exists (even if null/empty array)
                    return ('listPhase' in project) || ('ListPhase' in project);
                case 'S':
                    // Show Stage row if property exists (even if null/empty array)
                    return ('listStage' in project) || ('ListStage' in project);
                case 'TM':
                    // Show Task/Milestone row if property exists (even if null/empty array)
                    return ('listTask' in project) || ('ListTask' in project) ||
                           ('listMilestone' in project) || ('ListMilestone' in project) ||
                           ('ListMileStone' in project);
                default:
                    return false;
            }
        },
        getSettingName(setting) {
            switch(setting) {
                case 'P':
                    return 'Phase';
                case 'S':
                    return 'Stage';
                case 'TM':
                    return 'Task/Milestone';
                default:
                    return '';
            }
        },
        hasProjectDates(project) {
            // Check if project has start and end dates
            return project && (project.projectStartDate || project.projectEndDate);
        },
        getDynamicHeight(setting) {
            // Try to get height from cached DOM measurements first
            const cacheKey = `${setting}-${this.activeZoom}`;
            if (this.resourceLineHeights[cacheKey]) {
                return this.resourceLineHeights[cacheKey];
            }
            
            // Fallback: Calculate height based on resource-line height from RoadMapResourceData
            // Resource-line height is 45px (from RoadMapResourceData.vue CSS)
            // This matches the cell height for all settings (P, S, TM)
            let baseHeight = 45; // Base resource-line height from RoadMapResourceData
            
            // The height should match the resource-line height regardless of zoom level
            // as per RoadMapResourceData.vue: .resource-line { height: 45px; }
            return baseHeight;
        },
        updateHeightsFromDOM() {
            // Find corresponding resource-line elements in RoadMapResourceData
            // and get their actual heights to match sidebar heights dynamically
            this.$nextTick(() => {
                if (!this.roadMapData || this.roadMapData.length === 0) {
                    // Reset to default if no data
                    this.selectedSettings.forEach(setting => {
                        const cacheKey = `${setting}-${this.activeZoom}`;
                        this.resourceLineHeights[cacheKey] = 45;
                    });
                    return;
                }
                
                let heightsUpdated = false;
                
                // For each setting type, find the corresponding resource-line in the DOM
                this.selectedSettings.forEach(setting => {
                    const settingName = this.getSettingName(setting);
                    
                    // Find resource-line elements with matching data-resource-id
                    const resourceLines = document.querySelectorAll(
                        `.resource-line[data-resource-id="${settingName}"]`
                    );
                    
                    if (resourceLines.length > 0) {
                        // Get the height from the first matching resource-line
                        // All resource-lines should have the same height (45px from CSS)
                        const firstLine = resourceLines[0];
                        const computedStyle = window.getComputedStyle(firstLine);
                        const height = parseFloat(computedStyle.height) || parseFloat(computedStyle.minHeight) || 45;
                        
                        // Cache the height for this setting and zoom combination
                        const cacheKey = `${setting}-${this.activeZoom}`;
                        const oldHeight = this.resourceLineHeights[cacheKey];
                        this.resourceLineHeights[cacheKey] = height;
                        
                        // Check if height changed
                        if (oldHeight !== height) {
                            heightsUpdated = true;
                        }
                    } else {
                        // If not found in DOM yet, use default height from RoadMapResourceData CSS
                        const cacheKey = `${setting}-${this.activeZoom}`;
                        const oldHeight = this.resourceLineHeights[cacheKey];
                        this.resourceLineHeights[cacheKey] = 45; // Default from .resource-line { height: 45px; }
                        
                        if (oldHeight !== 45) {
                            heightsUpdated = true;
                        }
                    }
                });
                
                // Force re-render only if heights changed
                if (heightsUpdated) {
                    this.$forceUpdate();
                }
            });
        },
        setupHeightObserver() {
            // Set up MutationObserver to watch for changes in resource-line elements
            if (typeof MutationObserver !== 'undefined') {
                this.heightObserver = new MutationObserver(() => {
                    this.updateHeightsFromDOM();
                });
                
                // Observe the resources container for changes
                this.$nextTick(() => {
                    const resourcesContainer = document.querySelector('#resourcesmaindata, #resources, .divresources');
                    if (resourcesContainer) {
                        this.heightObserver.observe(resourcesContainer, {
                            childList: true,
                            subtree: true,
                            attributes: true,
                            attributeFilter: ['style', 'class']
                        });
                    }
                });
            }
        }
    }
}
</script>

<style scoped>
.sidebar-content {
    height: 100%;
    max-height: 100vh;
    overflow-y: auto;
    overflow-x: hidden;
    -webkit-overflow-scrolling: touch;
    position: relative;
}

.flying {
    padding: 10px;
    font-weight: bold;
    border-bottom: 1px solid #ddd;
    position: relative;
    margin-top:0px; margin-bottom:0px; min-height: 84px;
}
.flyingdown{ position: relative; padding: 10px; font-weight: bold; border-bottom: 1px solid #ddd!important;}

.resource { border-bottom: 1px solid #eee;}

</style>

