<template>  
<div class="time-periods modern-roadmap">
    <nav class="date-controls roadProjectmap modern-header" :style="getHeaderStyle()">
        <div class="header-content">
            <i class="fa fa-calendar-alt header-icon"></i>
            <span class="header-text">{{ $t('Projects') }}</span>
        </div>
    </nav>
    <div id="time-periods" class="time-periods-container" :style="{ width: totalWidth + 'px' }">
        <div v-for="(period, index) in timePeriods" :key="index" 
             class="unit-group modern-unit-group" 
             :class="{ 
                 'current': period.isCurrent,
                 'zoom-week': activeZoom === 'Week',
                 'zoom-month': activeZoom === 'Month',
                 'zoom-quarter': activeZoom === 'Quarter',
                 'zoom-year': activeZoom === 'Year'
             }"
             :style="{ width: period.width + 'px' }"
             :data-first-date="period.firstDateFormatted" 
             :data-last-date="period.lastDateFormatted"
             :count="period.count">
            <!-- Main Header -->
            <div class="period-header" v-if="period.label" :style="getPeriodHeaderStyle(index)">
                <h2 class="period-label">{{ period.label }}</h2>
            </div>
            <!-- Sub Header with Columns -->
            <div class="units modern-units" v-if="period.subPeriods && period.subPeriods.length > 0">
                <div v-for="(subPeriod, subIndex) in period.subPeriods" :key="subIndex" 
                     class="sub-period-group"
                     :style="getSubPeriodStyle()">
                    <div class="sub-period-header" :style="getSubPeriodHeaderStyle(index, subIndex)">
                        <span class="sub-period-label">{{ subPeriod.label }}</span>
                    </div>
                    <!-- For Week view: show days inside each week -->
                    <!-- <div v-if="activeZoom === 'Week' && subPeriod.days && subPeriod.days.length > 0" 
                         class="days-container">
                        <div v-for="(day, dayIndex) in subPeriod.days" :key="dayIndex" 
                             class="cal-unit modern-cal-unit" 
                             :class="{ 
                                 'current': day.isCurrent,
                                 'weekend': isWeekend(day.dayName),
                                 'today': day.isCurrent
                             }"
                             :data-date="day.dataDate || day.dateFormatted"
                             :style="getDayCellStyle()">
                            <div class="day-content">
                                <span v-if="day.dayName" class="day-name">{{ day.dayName }}</span>
                                <span v-if="day.dateNum" class="day-number">{{ day.dateNum }}</span>
                            </div>
                        </div>
                    </div> -->
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import moment from 'moment';

export default {
    name: 'RoadMapTimePeriod',
    props: {
        fromDate: {
            type: Date,
            required: true
        },
        toDate: {
            type: Date,
            required: true
        },
        activeZoom: {
            type: String,
            default: 'Week'
        }
    },
    computed: {
        timePeriods() {
            const periods = [];
            const currentDate = new Date();
            currentDate.setHours(0, 0, 0, 0);
            
            switch(this.activeZoom) {
                case 'Week':
                    return this.generateWeekPeriods(currentDate);
                case 'Month':
                    return this.generateMonthPeriods(currentDate);
                case 'Quarter':
                    return this.generateQuarterPeriods(currentDate);
                case 'Year':
                    return this.generateYearPeriods(currentDate);
                default:
                    return this.generateWeekPeriods(currentDate);
            }
        },
        totalWidth() {
            return this.timePeriods.reduce((sum, period) => sum + period.width, 0);
        }
    },
    methods: {
        // Get dynamic header background based on zoom level
        getHeaderStyle() {
            const gradients = {
                'Week': 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)',
                'Month': 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)',
                'Quarter': 'linear-gradient(135deg, #fa709a 0%, #fee140 100%)',
                'Year': 'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)'
            };
            return {
                background: gradients[this.activeZoom] || gradients['Week'],
                fontSize: '18px',
                paddingLeft: '20px',
                paddingRight: '20px',
                paddingTop: '16px',
                paddingBottom: '16px',
                color: '#fff',
                fontWeight: 'bold',
                boxShadow: '0 2px 8px rgba(0, 0, 0, 0.1)'
            };
        },
        // Get different color for each period header
        getPeriodHeaderStyle(index) {
            const colors = [
                'linear-gradient(135deg, #667eea 0%, #5550b0 100%)',
                'linear-gradient(135deg, #4c74c5 0%, #3c66bb 100%)',                
                'linear-gradient(135deg, #0286d3 0%, #007bc2 100%)',
                'linear-gradient(135deg, #3aa2ca 0%, #339abb 100%)',
                'linear-gradient(135deg, #29bbab 0%, #05a190 100%)',
                'linear-gradient(135deg, #4bb18d 0%, #239b63 100%)',
                'linear-gradient(135deg, #8b9a75 0%, #718c72 100%)',
                'linear-gradient(135deg, #a28e75 0%, #a66c59 100%)',               
                'linear-gradient(135deg, #af706f 0%, #986657 100%)',
                'linear-gradient(135deg, #a06763 0%, #855f6b 100%)',
                'linear-gradient(135deg, #988586 0%, #765f6f 100%)',
                'linear-gradient(135deg, #7f627d 0%, #5b405b 100%)'
                
            ];
            return {
                background: colors[index % colors.length]
            };
        },
        // Get sub-period header style (for weeks/months/quarters)
        getSubPeriodHeaderStyle(periodIndex, subIndex) {
            const colors = [
                'linear-gradient(135deg, rgba(102, 126, 234, 0.15) 0%, rgba(118, 75, 162, 0.15) 100%)',
                'linear-gradient(135deg, rgba(240, 123, 251, 0.15) 0%, rgba(245, 215, 108, 0.15) 100%)',
                'linear-gradient(135deg, rgba(79, 172, 254, 0.15) 0%, rgba(0, 242, 254, 0.15) 100%)',
                'linear-gradient(135deg, rgba(67, 233, 123, 0.15) 0%, rgba(56, 249, 215, 0.15) 100%)'
            ];
            return {
                background: colors[subIndex % colors.length],
                borderBottom: '1px solid rgba(0, 0, 0, 0.1)'
            };
        },
        // Week view: Main header = Week, Sub header = Days (7 columns per week)
        generateWeekPeriods(currentDate) {
            const periods = [];
            const startDate = new Date(this.fromDate);
            startDate.setHours(0, 0, 0, 0);
            const endDate = new Date(this.toDate);
            endDate.setHours(23, 59, 59, 999);
            
            // Get first day of week
            let first = startDate.getDate() - startDate.getDay() + 1;
            let currentWeekStart = new Date(startDate);
            currentWeekStart.setDate(first);
            currentWeekStart.setHours(0, 0, 0, 0);
            
            while (currentWeekStart <= endDate) {
                const weekEnd = new Date(currentWeekStart);
                weekEnd.setDate(weekEnd.getDate() + 6);
                weekEnd.setHours(23, 59, 59, 999);
                
                // Generate 7 days for this week (sub-periods)
                const days = [];
                let dayCounter = new Date(currentWeekStart);
                for (let j = 0; j < 7 && dayCounter <= endDate; j++) {
                    const dayDate = new Date(dayCounter);
                    const isCurrentDay = this.isSameDay(dayDate, currentDate);
                    days.push({
                        date: new Date(dayDate),
                        dateNum: dayDate.getDate(),
                        dayName: this.weekdays(dayDate.getDay()),
                        monthName: this.monthName(dayDate.getMonth()),
                        dateFormatted: `${dayDate.getFullYear()}-${dayDate.getMonth() + 1}-${dayDate.getDate()}`,
                        dataDate: `${dayDate.getFullYear()}-${dayDate.getMonth()}-${dayDate.getDate()}`,
                        isCurrent: isCurrentDay
                    });
                    dayCounter.setDate(dayCounter.getDate() + 1);
                }
                
                // Week label
                let weekLabel = '';
                if (weekEnd.getMonth() !== currentWeekStart.getMonth()) {
                    weekLabel = `${currentWeekStart.getDate()} ${this.monthName(currentWeekStart.getMonth())} - ${weekEnd.getDate()} ${this.monthName(weekEnd.getMonth())}, ${weekEnd.getFullYear()}`;
                } else {
                    weekLabel = `${currentWeekStart.getDate()} - ${weekEnd.getDate()} ${this.monthName(currentWeekStart.getMonth())}, ${currentWeekStart.getFullYear()}`;
                }
                
                // Create sub-periods (one for each day)
                const subPeriods = days.map(day => ({
                    label: `${day.dayName} ${day.dateNum}`,
                    firstDate: day.date,
                    lastDate: day.date,
                    days: [day] // Single day in each sub-period
                }));
                
                periods.push({
                    label: weekLabel,
                    firstDate: new Date(currentWeekStart),
                    lastDate: new Date(weekEnd),
                    firstDateFormatted: `${currentWeekStart.getFullYear()}-${currentWeekStart.getMonth() + 1}-${currentWeekStart.getDate()}`,
                    lastDateFormatted: `${weekEnd.getFullYear()}-${weekEnd.getMonth() + 1}-${weekEnd.getDate()}`,
                    width: 7 * 65, // 7 days * 30px each
                    isCurrent: this.isDateInRange(currentDate, currentWeekStart, weekEnd),
                    subPeriods: subPeriods
                });
                
                currentWeekStart.setDate(currentWeekStart.getDate() + 7);
            }
            
            return periods;
        },
        // Month view: Main header = Month, Sub header = Weeks (4 columns per month)
        generateMonthPeriods(currentDate) {
            const periods = [];
            const startDate = new Date(this.fromDate);
            startDate.setHours(0, 0, 0, 0);
            const endDate = new Date(this.toDate);
            endDate.setHours(23, 59, 59, 999);
            
            const monthdiff = this.monthDifference(startDate, endDate);
            
            for (let i = 0; i < monthdiff; i++) {
                const monthStart = new Date(startDate.getFullYear(), startDate.getMonth() + i, 1);
                const monthEnd = new Date(startDate.getFullYear(), startDate.getMonth() + i + 1, 0);
                monthEnd.setHours(23, 59, 59, 999);
                
                // Get first day of week for month start
                let weekStart = new Date(monthStart);
                const firstDayOfWeek = weekStart.getDay();
                weekStart.setDate(weekStart.getDate() - firstDayOfWeek);
                weekStart.setHours(0, 0, 0, 0);
                
                // Generate weeks for the month (sub-periods)
                const weeks = [];
                let currentWeek = new Date(weekStart);
                let weekCount = 0;
                
                while (currentWeek <= monthEnd && weekCount < 6) { // Max 6 weeks to handle month boundaries
                    const weekEnd = new Date(currentWeek);
                    weekEnd.setDate(weekEnd.getDate() + 6);
                    weekEnd.setHours(23, 59, 59, 999);
                    
                    // Only include weeks that overlap with the month
                    if (weekEnd >= monthStart && currentWeek <= monthEnd) {
                        weekCount++;
                        const weekLabel = `Week ${weekCount}`;
                        
                        weeks.push({
                            label: weekLabel,
                            firstDate: new Date(currentWeek),
                            lastDate: new Date(weekEnd),
                            firstDateFormatted: `${currentWeek.getFullYear()}-${currentWeek.getMonth() + 1}-${currentWeek.getDate()}`,
                            lastDateFormatted: `${weekEnd.getFullYear()}-${weekEnd.getMonth() + 1}-${weekEnd.getDate()}`
                        });
                    }
                    
                    currentWeek.setDate(currentWeek.getDate() + 7);
                }
                
                // Limit to 4 weeks per month (or actual weeks if less)
                const finalWeeks = weeks.slice(0, 4);
                
                const monthLabel = `${this.monthName(monthStart.getMonth())} ${monthStart.getFullYear()}`;
                const totalwidth = finalWeeks.length * 103.125; // 4 weeks * 80px each (wider than day columns)
                
                periods.push({
                    label: monthLabel,
                    firstDate: new Date(monthStart),
                    lastDate: new Date(monthEnd),
                    firstDateFormatted: `${monthStart.getFullYear()}-${monthStart.getMonth() + 1}-1`,
                    lastDateFormatted: `${monthEnd.getFullYear()}-${monthEnd.getMonth() + 1}-${monthEnd.getDate()}`,
                    width: totalwidth,
                    isCurrent: monthStart.getMonth() === currentDate.getMonth() && monthStart.getFullYear() === currentDate.getFullYear(),
                    subPeriods: finalWeeks
                });
            }
            
            return periods;
        },
        // Quarter view: Main header = Quarter, Sub header = Months (3 columns per quarter)
        generateQuarterPeriods(currentDate) {
            const periods = [];
            const startDate = new Date(this.fromDate);
            startDate.setHours(0, 0, 0, 0);
            const endDate = new Date(this.toDate);
            endDate.setHours(23, 59, 59, 999);
            
            // Calculate quarters
            const startQuarter = Math.floor(startDate.getMonth() / 3);
            const endQuarter = Math.floor(endDate.getMonth() / 3);
            const startYear = startDate.getFullYear();
            const endYear = endDate.getFullYear();
            
            let currentYear = startYear;
            let currentQuarter = startQuarter;
            
            while (currentYear < endYear || (currentYear === endYear && currentQuarter <= endQuarter)) {
                const quarterStartMonth = currentQuarter * 3;
                const quarterStart = new Date(currentYear, quarterStartMonth, 1);
                const quarterEnd = new Date(currentYear, quarterStartMonth + 3, 0);
                quarterEnd.setHours(23, 59, 59, 999);
                
                // Generate 3 months for this quarter (sub-periods)
                const months = [];
                for (let m = 0; m < 3; m++) {
                    const monthStart = new Date(currentYear, quarterStartMonth + m, 1);
                    const monthEnd = new Date(currentYear, quarterStartMonth + m + 1, 0);
                    monthEnd.setHours(23, 59, 59, 999);
                    
                    months.push({
                        label: this.monthName(quarterStartMonth + m),
                        firstDate: new Date(monthStart),
                        lastDate: new Date(monthEnd),
                        firstDateFormatted: `${monthStart.getFullYear()}-${monthStart.getMonth() + 1}-1`,
                        lastDateFormatted: `${monthEnd.getFullYear()}-${monthEnd.getMonth() + 1}-${monthEnd.getDate()}`
                    });
                }
                
                const quarterLabel = `Q${currentQuarter + 1} ${currentYear}`;
                const totalwidth = 3 * 275; // 3 months * 100px each
                
                periods.push({
                    label: quarterLabel,
                    firstDate: new Date(quarterStart),
                    lastDate: new Date(quarterEnd),
                    firstDateFormatted: `${quarterStart.getFullYear()}-${quarterStart.getMonth() + 1}-1`,
                    lastDateFormatted: `${quarterEnd.getFullYear()}-${quarterEnd.getMonth() + 1}-${quarterEnd.getDate()}`,
                    width: totalwidth,
                    isCurrent: currentYear === currentDate.getFullYear() && currentQuarter === Math.floor(currentDate.getMonth() / 3),
                    subPeriods: months
                });
                
                currentQuarter++;
                if (currentQuarter > 3) {
                    currentQuarter = 0;
                    currentYear++;
                }
            }
            
            return periods;
        },
        // Year view: Main header = Year, Sub header = Quarters (ALL quarters for each year)
        // Year view shows full years regardless of start/end dates
        generateYearPeriods(currentDate) {
            const periods = [];
            const startDate = new Date(this.fromDate);
            startDate.setHours(0, 0, 0, 0);
            const endDate = new Date(this.toDate);
            endDate.setHours(23, 59, 59, 999);
            
            const yeardiff = this.yearDifference(startDate, endDate);
            
            // Generate ALL quarters for ALL years in the range
            for (let i = 0; i < yeardiff; i++) {
                const yearStart = new Date(startDate.getFullYear() + i, 0, 1);
                const yearEnd = new Date(startDate.getFullYear() + i, 11, 31);
                yearEnd.setHours(23, 59, 59, 999);
                
                // Generate ALL 4 quarters for this year (sub-periods)
                const quarters = [];
                for (let q = 0; q < 4; q++) {
                    const quarterStartMonth = q * 3;
                    const quarterStart = new Date(yearStart.getFullYear(), quarterStartMonth, 1);
                    const quarterEnd = new Date(yearStart.getFullYear(), quarterStartMonth + 3, 0);
                    quarterEnd.setHours(23, 59, 59, 999);
                    
                    quarters.push({
                        label: `Q${q + 1}`,
                        firstDate: new Date(quarterStart),
                        lastDate: new Date(quarterEnd),
                        firstDateFormatted: `${quarterStart.getFullYear()}-${quarterStart.getMonth() + 1}-1`,
                        lastDateFormatted: `${quarterEnd.getFullYear()}-${quarterEnd.getMonth() + 1}-${quarterEnd.getDate()}`
                    });
                }
                
                const yearLabel = yearStart.getFullYear().toString();
                const totalwidth = 4 * 206.25; // 4 quarters * 120px each
                
                periods.push({
                    label: yearLabel,
                    firstDate: new Date(yearStart),
                    lastDate: new Date(yearEnd),
                    firstDateFormatted: `${yearStart.getFullYear()}-1-1`,
                    lastDateFormatted: `${yearEnd.getFullYear()}-12-31`,
                    width: totalwidth,
                    isCurrent: yearStart.getFullYear() === currentDate.getFullYear(),
                    subPeriods: quarters
                });
            }
            
            return periods;
        },
        getSubPeriodStyle() {
            const baseStyle = {
                display: 'inline-block',
                verticalAlign: 'top',
                borderRight: '1px solid #e0e0e0'
            };
            switch(this.activeZoom) {
                case 'Week':
                    baseStyle.width = '65px';
                    baseStyle.minWidth = '65px';
                    break;
                case 'Month':
                    baseStyle.width = '103.125px';
                    baseStyle.minWidth = '103.125px';
                    break;
                case 'Quarter':
                    baseStyle.width = '275px';
                    baseStyle.minWidth = '275px';
                    break;
                case 'Year':
                    baseStyle.width = '206.25px';
                    baseStyle.minWidth = '206.25px';
                    break;
            }
            return baseStyle;
        },
        getDayCellStyle() {
            return {
                width: '30px',
                minWidth: '30px',
                height: '30px'
            };
        },
        daysBetweenDates(start, end) {
            const oneDay = 24 * 60 * 60 * 1000;
            const firstDate = new Date(start);
            firstDate.setHours(0, 0, 0, 0);
            const secondDate = new Date(end);
            secondDate.setHours(0, 0, 0, 0);
            return Math.round(Math.abs((firstDate.getTime() - secondDate.getTime()) / oneDay)) + 1;
        },
        isDateInRange(date, start, end) {
            const d = new Date(date);
            const s = new Date(start);
            const e = new Date(end);
            d.setHours(0, 0, 0, 0);
            s.setHours(0, 0, 0, 0);
            e.setHours(0, 0, 0, 0);
            return d >= s && d <= e;
        },
        isSameDay(date1, date2) {
            const d1 = new Date(date1);
            const d2 = new Date(date2);
            return d1.getFullYear() === d2.getFullYear() &&
                   d1.getMonth() === d2.getMonth() &&
                   d1.getDate() === d2.getDate();
        },
        weekdays(index) {
            const weekdays = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
            return weekdays[index] || '';
        },
        monthName(monthIndex) {
            const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
            return months[monthIndex] || '';
        },
        isWeekend(dayName) {
            return dayName === 'Sat' || dayName === 'Sun';
        },
        weekDaysBetweenDates(fromDate, toDate) {
            if (!fromDate || !toDate) return 0;
            const ONE_WEEK = 1000 * 60 * 60 * 24 * 7;
            const date1_ms = fromDate.getTime();
            const date2_ms = toDate.getTime();
            const difference_ms = Math.abs(date2_ms - date1_ms);
            return Math.floor(difference_ms / ONE_WEEK) + 1;
        },
        monthDifference(fromDate, toDate) {
            if (!fromDate || !toDate) return 0;
            const from = new Date(fromDate);
            const to = new Date(toDate);
            const yearDiff = to.getFullYear() - from.getFullYear();
            const monthDiff = to.getMonth() - from.getMonth();
            return yearDiff * 12 + monthDiff + 1;
        },
        yearDifference(fromDate, toDate) {
            if (!fromDate || !toDate) return 0;
            const from = new Date(fromDate);
            const to = new Date(toDate);
            return to.getFullYear() - from.getFullYear() + 1;
        }
    }
}
</script>

<style scoped>
